msg.operation = "find";
msg.collection = "cr_catalogues";
msg.payload = [
    {},
    { projection: { catalog: 1, uniqueId: 1, _id: 0 } }
];
return msg;

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const catalogs = docs.map(d => {
    const c = d.catalog || d;
    return {
        uniqueId: d.uniqueId || c.catalogId || d._id,
        catalogId: c.catalogId || d.uniqueId,
        catalogName: c.catalogName || c.catalogId || '-',
        owner: c.owner || '-',
        strategy: c.strategy || 'none',
        baseEndpoint: c.baseEndpoint || '',
        enabled: c.enabled !== false,
        protocol: c.protocol || 'Query interface',
        updatedAt: c.updatedAt || '',
        auth: c.auth || 'none',
        authLoginEndpoint: c.authLoginEndpoint || '',
        authUsername: c.authUsername || '',
        authPassword: c.authPassword || '',
        authPayloadTemplate: c.authPayloadTemplate || '',
        authTokenPath: c.authTokenPath || 'token',
        authTokenInjection: c.authTokenInjection || 'body',
        authTokenFieldName: c.authTokenFieldName || 'token',
        authTokenPrefix: c.authTokenPrefix || '',
        authStaticToken: c.authStaticToken || '',
        authApiKey: c.authApiKey || '',
        authApiKeyHeader: c.authApiKeyHeader || 'X-API-Key',
        responseRootPath: c.responseRootPath || '',
        responseAssetIdField: c.responseAssetIdField || '',
        responseAssetNameField: c.responseAssetNameField || '',
        responseAssetTypeField: c.responseAssetTypeField || '',
        sourceData: c.sourceData || null,
        sourceFileName: c.sourceFileName || '',
        mimeType: c.mimeType || ''
    };
});
msg.response = {
    action: "getHarvestCatalogues",
    status: "success",
    catalogs: catalogs
};
delete msg.payload;
return msg;

const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
let rnd = '';
for (let i = 0; i < 12; i++) rnd += chars[Math.floor(Math.random() * chars.length)];
const runId = 'run-' + Date.now().toString(36) + rnd;

const catalogues = msg.data?.catalogues || [];
const catNames = catalogues.map(c => c.catalogName).filter(Boolean);
const now = new Date();
const nowISO = now.toISOString();
const nowShort = nowISO.replace('T', ' ').slice(0, 19);

function resolvePath(obj, path) {
    if (!path || !obj) return obj;
    const parts = path.split('.');
    let cur = obj;
    for (const p of parts) {
        if (cur == null || typeof cur !== 'object') return undefined;
        cur = cur[p];
    }
    return cur;
}

function extractEntries(data, rootPath) {
    if (!data) return [];
    if (rootPath) {
        const resolved = resolvePath(data, rootPath);
        if (Array.isArray(resolved)) return resolved;
        if (resolved && typeof resolved === 'object') return [resolved];
    }
    if (Array.isArray(data)) return data;
    if (data['dcat:dataset'] && Array.isArray(data['dcat:dataset'])) return data['dcat:dataset'];
    if (data.dataset && Array.isArray(data.dataset)) return data.dataset;
    if (data.datasets && Array.isArray(data.datasets)) return data.datasets;
    if (data.data && Array.isArray(data.data)) return data.data;
    if (data.results && Array.isArray(data.results)) return data.results;
    if (data.result && data.result.results && Array.isArray(data.result.results)) return data.result.results;
    if (data.items && Array.isArray(data.items)) return data.items;
    if (data.records && Array.isArray(data.records)) return data.records;
    if (data.entries && Array.isArray(data.entries)) return data.entries;
    if (data.assets && Array.isArray(data.assets)) return data.assets;
    if (data.catalogs && Array.isArray(data.catalogs)) return data.catalogs;
    if (data.title || data.name || data.identifier || data['@type']) return [data];
    if (data._id || data.requestId != null || data.companyDetails) return [data];
    const skipKeys = ['auditInfo','approveInfo','decisionHistory','errors','warnings','logs'];
    for (const key of Object.keys(data)) {
        if (Array.isArray(data[key]) && data[key].length > 0 && typeof data[key][0] === 'object' && !skipKeys.includes(key)) return data[key];
    }
    return [data];
}

function extractName(entry, nameField) {
    if (!entry || typeof entry !== 'object') return 'Unknown Asset';
    if (nameField) { const v = resolvePath(entry, nameField); if (v && typeof v === 'string' && v.trim()) return v; }
    const cands = ['title','name','catalogName','label','displayName','companyName','organisationName','organization','fullName','shortName','legalName','tradingName','firma'];
    for (const f of cands) { if (entry[f] && typeof entry[f] === 'string' && entry[f].trim()) return entry[f]; }
    const cd = entry.companyDetails;
    if (cd && typeof cd === 'object') {
        if (cd['A.1.1.1'] && typeof cd['A.1.1.1'] === 'string') return cd['A.1.1.1'];
        if (cd['A.2.1.1'] && typeof cd['A.2.1.1'] === 'string') return cd['A.2.1.1'];
        for (const f of cands) { if (cd[f] && typeof cd[f] === 'string' && cd[f].trim()) return cd[f]; }
    }
    if (entry.createdBy && entry.createdBy.fullName && typeof entry.createdBy.fullName === 'string') return entry.createdBy.fullName;
    for (const key of Object.keys(entry)) {
        const nested = entry[key];
        if (nested && typeof nested === 'object' && !Array.isArray(nested)) {
            for (const f of cands) { if (nested[f] && typeof nested[f] === 'string' && nested[f].trim()) return nested[f]; }
        }
    }
    for (const key of Object.keys(entry)) {
        const val = entry[key];
        if (typeof val === 'string' && val.length > 2 && val.length < 200 && !/^[\d\-:.TZ]+$/.test(val) && !/^[0-9a-f]{24}$/i.test(val) && !key.startsWith('_')) return val;
    }
    return 'Unknown Asset';
}

function extractId(entry, idField) {
    if (idField) { const v = resolvePath(entry, idField); if (v) return String(v); }
    return String(entry.identifier || entry.id || entry._id || entry.requestId || entry.uuid || ('remote-' + Math.random().toString(36).slice(2, 10)));
}

function extractType(entry, typeField) {
    if (typeField) { const v = resolvePath(entry, typeField); if (v) return String(v); }
    const cd = entry.companyDetails;
    return String(entry['@type'] || entry.type || entry.assetType || (cd && cd['A.1.1.0']) || (cd && cd['A.2.1.4']) || 'dcat:Dataset');
}

const provenance = [];
const logs = [];
const assetDetails = [];
const lcDocs = [];
let assetCounter = 0;

for (const cat of catalogues) {
    const catName = cat.catalogName || cat.uniqueId || 'Unknown';
    const catId = cat.uniqueId || cat.catalogId || '';
    const strategy = cat.strategy || 'none';
    const rootPath = cat.responseRootPath || '';
    const idField = cat.responseAssetIdField || '';
    const nameField = cat.responseAssetNameField || '';
    const typeField = cat.responseAssetTypeField || '';
    const sourceData = cat.sourceData || null;
    let entries = [];
    if (sourceData) {
        entries = extractEntries(sourceData, rootPath);
        logs.push({ runId, assetId: '', level: 'info', message: 'Extracted ' + entries.length + ' entries from sourceData', catalogue: catName, timestamp: nowISO });
    }

    for (let i = 0; i < entries.length; i++) {
        assetCounter++;
        const entry = entries[i];
        if (!entry || typeof entry !== 'object') continue;
        const assetId = 'asset-' + runId + '-' + assetCounter;
        const lcId = 'lc-' + runId + '-' + assetCounter;
        const rawId = extractId(entry, idField);
        const assetName = extractName(entry, nameField);
        const assetType = extractType(entry, typeField);
        const domain = entry.domain || entry.theme || entry.category || catName;

        assetDetails.push({ assetId: assetId, title: assetName, catalogue: catName, status: 'success', strategy: strategy, sourceId: rawId });
        lcDocs.push({
            uniqueId: lcId,
            id: lcId,
            assets: assetName,
            title: assetName,
            type: assetType,
            name: catName,
            domain: domain,
            updated: nowShort,
            integrationStatus: 'Active',
            sourceCatalogue: catName,
            sourceCatalogueId: catId,
            harvestRunId: runId,
            remoteAssetId: rawId,
            originalForm: entry,
            transformedForm: null,
            sourceAssetId: rawId,
            harvestedAt: nowISO,
            createdAt: nowISO
        });
        provenance.push({ runId: runId, assetId: assetId, title: assetName, catalogue: catName, action: 'imported', strategy: strategy, timestamp: nowISO, status: 'success', sourceId: rawId });
        logs.push({ runId: runId, assetId: assetId, level: 'info', message: 'Imported: ' + assetName, catalogue: catName, timestamp: nowISO });
    }

    logs.push({ runId: runId, assetId: '', level: 'info', message: 'Harvest completed for ' + catName + ': ' + entries.length + ' entries processed', catalogue: catName, timestamp: nowISO });
}

const successCount = assetDetails.filter(a => a.status === 'success').length;
const errorCount = assetDetails.filter(a => a.status === 'error').length;

const run = {
    uniqueId: runId,
    catalogueName: catNames.join(', ') || 'Harvest',
    scope: msg.data?.scope || {},
    lifecycle: msg.data?.lifecycle || {},
    status: 'completed',
    startedAt: nowShort,
    totalAssets: assetCounter,
    assetsAdded: successCount,
    successCount: successCount,
    errorCount: errorCount,
    result: errorCount === 0 ? 'Success' : 'Partial',
    tool: 'Harvester',
    provenance: provenance,
    logs: logs,
    assetIds: lcDocs.map(a => a.id)
};

const msg1 = { _harvestRun: run, _lcDocs: lcDocs, operation: 'insertOne', collection: 'hv_runs', payload: run, _msgid: msg._msgid, _uib: msg._uib, _socketId: msg._socketId };
return msg1;

const lcDocs = msg._lcDocs || [];
if (lcDocs.length === 0) {
    // No assets to insert, skip to response
    return msg;
}
msg.operation = 'insertMany';
msg.collection = 'lc_assets';
msg.payload = [lcDocs];
return msg;

const run = msg._harvestRun || {};
const lcDocs = msg._lcDocs || [];
delete msg._harvestRun;
delete msg._lcDocs;

msg.response = {
    action: 'startHarvest',
    status: 'success',
    run: run,
    allAssets: lcDocs,
    allProvenance: run.provenance || [],
    totalAssets: lcDocs.length,
    totalRuns: 1
};
delete msg.payload;
return msg;

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const runs = docs.map(d => {
    const r = Object.assign({}, d);
    delete r.provenance;
    delete r.logs;
    delete r.assets;
    return r;
});
runs.sort((a, b) => (b.startedAt || '').localeCompare(a.startedAt || ''));
msg.response = {
    action: 'listHarvestRuns',
    status: 'success',
    runs: runs
};
delete msg.payload;
return msg;

msg.operation = 'findOne';
msg.collection = 'hv_runs';
msg.payload = { uniqueId: msg.data.runId };
return msg;

const run = msg.payload || null;
msg.response = {
    action: 'getHarvestRunDetail',
    status: 'success',
    run: run
};
delete msg.payload;
return msg;

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const logs = [];
for (const d of docs) {
    if (Array.isArray(d.logs)) {
        for (const l of d.logs) logs.push(l);
    }
}
msg.response = {
    action: 'listHarvestLogs',
    status: 'success',
    logs: logs
};
delete msg.payload;
return msg;

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const provenance = [];
for (const d of docs) {
    if (Array.isArray(d.provenance)) {
        for (const p of d.provenance) provenance.push(p);
    }
}
msg.response = {
    action: 'listHarvestProvenance',
    status: 'success',
    provenance: provenance
};
delete msg.payload;
return msg;

msg.operation = 'updateOne';
msg.collection = 'hv_runs';
msg.payload = [
    { uniqueId: msg.data.runId },
    { $set: { status: 'paused' } }
];
msg._action = 'pauseHarvest';
return msg;

msg.operation = 'updateOne';
msg.collection = 'hv_runs';
msg.payload = [
    { uniqueId: msg.data.runId },
    { $set: { status: 'running' } }
];
msg._action = 'resumeHarvest';
return msg;

msg.operation = 'updateOne';
msg.collection = 'hv_runs';
msg.payload = [
    { uniqueId: msg.data.runId },
    { $set: { status: 'cancelled' } }
];
msg._action = 'cancelHarvest';
return msg;

msg.response = {
    action: msg._action || 'harvestControl',
    status: 'success'
};
delete msg._action;
delete msg.payload;
return msg;

var catalogues = (msg.data && msg.data.catalogues) ? msg.data.catalogues : [];
var queue = [];

for (var i = 0; i < catalogues.length; i++) {
    var cat = catalogues[i];
    if (cat.sourceData) continue;

    var endpoint = cat.baseEndpoint || '';
    if (!endpoint) continue;

    var authType = cat.auth || 'none';

    if (authType === 'token-login' && cat.authLoginEndpoint) {
        var body = (cat.authPayloadTemplate || '{"email":"{{username}}","password":"{{password}}"}').replace('{{username}}', cat.authUsername || '').replace('{{password}}', cat.authPassword || '');
        queue.push({ step: 'login', catIdx: i, url: cat.authLoginEndpoint, hdrs: { 'Content-Type': 'application/json', 'Accept': 'application/json' }, body: body, tokenPath: cat.authTokenPath || 'token', tokenPrefix: cat.authTokenPrefix || 'Bearer' });
    }

    var hdrs = { 'Accept': 'application/json', 'Content-Type': 'application/json' };
    if (authType === 'static-token' && cat.authStaticToken) {
        hdrs['Authorization'] = (cat.authTokenPrefix || 'Bearer') + ' ' + cat.authStaticToken;
    } else if (authType === 'api-key' && cat.authApiKey) {
        hdrs[cat.authApiKeyHeader || 'X-API-Key'] = cat.authApiKey;
    }
    queue.push({ step: 'data', catIdx: i, url: endpoint, hdrs: hdrs, body: '', catName: cat.catalogName || '' });
}

if (queue.length === 0) {
    return [null, msg];
}

msg._fetchQueue = queue;
msg._fetchIdx = 0;
var first = queue[0];
msg.url = first.url;
msg.method = 'POST';
msg.headers = first.hdrs;
msg.payload = first.body || '';
node.warn('[harvest] Fetching API: ' + first.url);
return [msg, null];

var queue = msg._fetchQueue || [];
var idx = msg._fetchIdx || 0;
var current = queue[idx];
var catalogues = (msg.data && msg.data.catalogues) ? msg.data.catalogues : [];

function resolvePath(obj, path) {
    if (!path || !obj) return obj;
    var parts = path.split('.');
    var cur = obj;
    for (var pi = 0; pi < parts.length; pi++) {
        if (cur == null || typeof cur !== 'object') return undefined;
        cur = cur[parts[pi]];
    }
    return cur;
}

if (current) {
    var status = msg.statusCode || 0;
    var data = msg.payload;
    if (typeof data === 'string') { try { data = JSON.parse(data); } catch(e) { data = null; } }

    if (current.step === 'login') {
        if (data && typeof data === 'object' && status >= 200 && status < 300) {
            var token = resolvePath(data, current.tokenPath || 'token');
            if (token) {
                for (var j = idx + 1; j < queue.length; j++) {
                    if (queue[j].catIdx === current.catIdx && queue[j].step === 'data') {
                        queue[j].hdrs['Authorization'] = (current.tokenPrefix || 'Bearer') + ' ' + String(token);
                        break;
                    }
                }
            }
        }
        node.warn('[harvest] Login ' + (status >= 200 && status < 300 ? 'OK' : 'failed HTTP ' + status) + ' for catalogue idx ' + current.catIdx);
    } else if (current.step === 'data') {
        if (data && typeof data === 'object' && status >= 200 && status < 300) {
            catalogues[current.catIdx].sourceData = data;
            node.warn('[harvest] Fetched API data for ' + (current.catName || 'catalogue') + ' (HTTP ' + status + ')');
        } else {
            node.warn('[harvest] API fetch failed for ' + (current.catName || 'catalogue') + ' (HTTP ' + status + ')');
        }
    }
}

var nextIdx = idx + 1;
msg._fetchIdx = nextIdx;

if (nextIdx < queue.length) {
    var next = queue[nextIdx];
    msg.url = next.url;
    msg.method = 'POST';
    msg.headers = next.hdrs;
    msg.payload = next.body || '';
    node.warn('[harvest] Next fetch: ' + next.url);
    return [msg, null];
}

delete msg._fetchQueue;
delete msg._fetchIdx;
msg.payload = '';
return [null, msg];
